mapper.select:
SELECT c.id, c.post_id, p.content AS post_content, c.user_id, c.content, c.like_count, c.status, c.created_at, u.nickname, u.avatar FROM forum_comments c LEFT JOIN forum_posts p ON c.post_id = p.id LEFT JOIN profiles u ON c.user_id = u.id WHERE c.deleted = 0
AND ( c.content LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') )
AND c.post_id = #{postId}
AND c.user_id = #{userId}
AND c.status = #{status}
ORDER BY c.created_at DESC
